const fs = require('fs');
const config = JSON.parse(fs.readFileSync('/home/node/config.json', 'utf8'));

const today = new Date().toISOString().split('T')[0];
let reminders = [];

try {
  const files = fs.readdirSync(config.knowledge_dir).filter(f => f.endsWith('.md'));
  for (const file of files) {
    try {
      const content = fs.readFileSync(config.knowledge_dir + '/' + file, 'utf8');
      const entries = content.split('---').filter(e => e.trim() && e.includes('##'));
      for (const entry of entries) {
        const reminderMatch = entry.match(/\*\*Reminder:\*\* (\d{4}-\d{2}-\d{2})/);
        if (reminderMatch && reminderMatch[1] === today) {
          const titleMatch = entry.match(/## \[(.+?)\]\((.+?)\)/);
          const voiceMatch = entry.match(/## 🎤 (.+)/);
          const imageMatch = entry.match(/## 🖼 (.+)/);
          const summaryMatch = entry.match(/> (.+)/);
          if (titleMatch || voiceMatch || imageMatch) {
            reminders.push({
              title: titleMatch?.[1] || voiceMatch?.[1] || imageMatch?.[1] || 'Reminder',
              url: titleMatch?.[2] || '',
              summary: summaryMatch?.[1] || ''
            });
          }
        }
      }
    } catch(e) {}
  }
} catch(e) {}

return { reminders, count: reminders.length, today };

const fs = require('fs');
const config = JSON.parse(fs.readFileSync('/home/node/config.json', 'utf8'));

const reminders = $('Check reminders').item.json.reminders;
const today = $('Check reminders').item.json.today;

let text = '⏰ Reminders for today — ' + today + '\n\n';
text += reminders.map((r, i) =>
  `${i + 1}. *${r.title}*\n${r.url}\n${r.summary}`
).join('\n\n');

await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://api.telegram.org/bot' + config.telegram_bot_token + '/sendMessage',
  headers: { 'Content-Type': 'application/json' },
  body: {
    chat_id: config.telegram_chat_id,
    text: text.slice(0, 4096)
  }
});

return { sent: true, count: reminders.length };

const fs = require('fs');
const config = JSON.parse(fs.readFileSync('/home/node/config.json', 'utf8'));

const { digest, totalCount } = $('Generate digest').item.json;
if (!digest || totalCount === 0) return { skipped: true };

await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://api.telegram.org/bot' + config.telegram_bot_token + '/sendMessage',
  headers: { 'Content-Type': 'application/json' },
  body: {
    chat_id: config.telegram_chat_id,
    text: digest.slice(0, 4096)
  }
});

return { sent: true };

const fs = require('fs');
const config = JSON.parse(fs.readFileSync('/home/node/config.json', 'utf8'));

// Load digest settings
let settings = {
  enabled: true,
  time: '09:00',
  summary: true,
  categories: true,
  voice: true,
  images: true,
  stats: true,
  motivation: true
};
try {
  settings = { ...settings, ...JSON.parse(fs.readFileSync(config.digest_settings_file, 'utf8')) };
} catch(e) {}

// Check if digest is enabled
if (!settings.enabled) {
  return { digest: null, totalCount: 0, skipped: true };
}

const today = new Date();
const yesterday = new Date(today);
yesterday.setDate(yesterday.getDate() - 1);
const yesterdayStr = yesterday.toISOString().split('T')[0];

// Also get last 7 days for stats comparison
const lastWeek = new Date(today);
lastWeek.setDate(lastWeek.getDate() - 8);
const lastWeekStr = lastWeek.toISOString().split('T')[0];

let totalCount = 0;
let linkCount = 0;
let voiceCount = 0;
let imageCount = 0;
let lastWeekTotal = 0;
let categorySections = [];
let linkEntries = [];
let voiceEntries = [];
let imageEntries = [];

try {
  const files = fs.readdirSync(config.knowledge_dir).filter(f => f.endsWith('.md'));

  for (const file of files) {
    try {
      const content = fs.readFileSync(config.knowledge_dir + '/' + file, 'utf8');
      const category = file.replace('.md', '');
      const entries = content.split('---').filter(e => e.trim() && e.includes('##'));

      // Count last week entries for stats
      if (settings.stats) {
        const weekEntries = entries.filter(e => {
          const dateMatch = e.match(/\*\*Saved:\*\* (\d{4}-\d{2}-\d{2})/);
          if (!dateMatch) return false;
          return dateMatch[1] >= lastWeekStr && dateMatch[1] < yesterdayStr;
        });
        lastWeekTotal += weekEntries.length;
      }

      // Get yesterday's entries
      const yesterdayEntries = entries.filter(e => {
        const dateMatch = e.match(/\*\*Saved:\*\* (\d{4}-\d{2}-\d{2})/);
        if (!dateMatch) return false;
        return dateMatch[1] === yesterdayStr;
      });

      if (yesterdayEntries.length === 0) continue;

      for (const e of yesterdayEntries) {
        const isVoice = e.includes('🎤');
        const isImage = e.includes('🖼');
        const isLink = !isVoice && !isImage;

        if (isVoice) {
          voiceCount++;
          totalCount++;
          if (settings.voice) {
            const title = e.match(/## 🎤 (.+)/)?.[1] || 'Voice note';
            const summary = e.match(/> (.+)/)?.[1] || '';
            let item = '🎤 ' + title;
            if (settings.summary && summary) item += '\n   ' + summary.slice(0, 100);
            voiceEntries.push(item);
          }
        } else if (isImage) {
          imageCount++;
          totalCount++;
          if (settings.images) {
            const title = e.match(/## 🖼 (.+)/)?.[1] || 'Image';
            const summary = e.match(/> (.+)/)?.[1] || '';
            let item = '🖼 ' + title;
            if (settings.summary && summary) item += '\n   ' + summary.slice(0, 100);
            imageEntries.push(item);
          }
        } else {
          linkCount++;
          totalCount++;
          const titleMatch = e.match(/## \[(.+?)\]\(/);
          const urlMatch = e.match(/## \[.+?\]\((.+?)\)/);
          const summary = e.match(/> (.+)/)?.[1] || '';
          const title = titleMatch?.[1] || 'Untitled';
          let item = '• ' + title;
          if (urlMatch) item += '\n  ' + urlMatch[1];
          if (settings.summary && summary) item += '\n  ' + summary.slice(0, 100);
          linkEntries.push({ item, category });
        }
      }

      // Group by category
      if (settings.categories) {
        const catItems = yesterdayEntries.map(e => {
          const isVoice = e.includes('🎤');
          const isImage = e.includes('🖼');
          const linkTitle = e.match(/## \[(.+?)\]\(/)?.[1];
          const voiceTitle = e.match(/## 🎤 (.+)/)?.[1];
          const imageTitle = e.match(/## 🖼 (.+)/)?.[1];
          const title = linkTitle || voiceTitle || imageTitle || 'Untitled';
          const urlMatch = e.match(/## \[.+?\]\((.+?)\)/);
          const summary = e.match(/> (.+)/)?.[1] || '';
          const icon = isVoice ? '🎤' : isImage ? '🖼' : '🔗';
          let item = icon + ' ' + title;
          if (urlMatch) item += '\n  ' + urlMatch[1];
          if (settings.summary && summary) item += '\n  ' + summary.slice(0, 100);
          return item;
        }).join('\n\n');
        categorySections.push('📂 *' + category + '* (' + yesterdayEntries.length + ')\n' + catItems);
      }
    } catch(e) {}
  }
} catch(e) {}

// Build digest message
if (totalCount === 0) {
  let digest = null;
  if (settings.motivation) {
    digest = '🌅 ' + yesterdayStr + '\n\nNothing saved yesterday. Today is a new day — save something interesting! 🔗';
  }
  return { digest, totalCount: 0, yesterdayStr };
}

let parts = [];

// Header
parts.push('🌅 *Daily Digest — ' + yesterdayStr + '*');
parts.push('You saved *' + totalCount + ' item' + (totalCount > 1 ? 's' : '') + '* yesterday');

// Stats comparison
if (settings.stats && lastWeekTotal > 0) {
  const avg = Math.round(lastWeekTotal / 7);
  const diff = totalCount - avg;
  if (diff > 0) parts.push('📈 ' + diff + ' more than your daily average (' + avg + '/day last week)');
  else if (diff < 0) parts.push('📉 ' + Math.abs(diff) + ' less than your daily average (' + avg + '/day last week)');
  else parts.push('📊 Right at your daily average (' + avg + '/day last week)');
}

parts.push('');

// Content by category or by type
if (settings.categories && categorySections.length > 0) {
  parts.push(categorySections.join('\n\n'));
} else {
  // Show by type
  if (settings.voice && voiceEntries.length > 0) {
    parts.push('🎤 *Voice notes (' + voiceCount + ')*\n' + voiceEntries.join('\n\n'));
  }
  if (settings.images && imageEntries.length > 0) {
    parts.push('🖼 *Images (' + imageCount + ')*\n' + imageEntries.join('\n\n'));
  }
  if (linkEntries.length > 0) {
    parts.push('🔗 *Links (' + linkCount + ')*\n' + linkEntries.map(l => l.item).join('\n\n'));
  }
}

// Motivation
if (settings.motivation) {
  const phrases = [
    'Keep building your knowledge vault! 🧠',
    'Great saves! Your future self will thank you. 💡',
    'Knowledge compounds — keep saving! 📚',
    'Another day, another step toward your goals. 🎯'
  ];
  parts.push('\n' + phrases[Math.floor(Math.random() * phrases.length)]);
}

const digest = parts.join('\n');
return { digest, totalCount, yesterdayStr };

const fs = require('fs');
const config = JSON.parse(fs.readFileSync('/home/node/config.json', 'utf8'));

let brokenLinks = [];
let checkedCount = 0;

try {
  const files = fs.readdirSync(config.knowledge_dir).filter(f => f.endsWith('.md'));
  for (const file of files) {
    try {
      const content = fs.readFileSync(config.knowledge_dir + '/' + file, 'utf8');
      const category = file.replace('.md', '');

      const linkMatches = [...content.matchAll(/## \[(.+?)\]\((https?:\/\/[^\)]+)\)/g)];
      for (const match of linkMatches) {
        const title = match[1];
        const url = match[2];

        // Skip platforms that always block
        if (url.includes('x.com') || url.includes('twitter.com') ||
            url.includes('instagram.com') || url.includes('tiktok.com') ||
            url.includes('t.me')) continue;

        checkedCount++;
        try {
          const response = await this.helpers.httpRequest({
            method: 'GET',
            url: url,
            headers: { 'User-Agent': 'Mozilla/5.0' },
            timeout: 8000,
            returnFullResponse: true
          });
          if (response.statusCode >= 400) {
            brokenLinks.push({ title, url, category, status: response.statusCode });
          }
        } catch(e) {
          brokenLinks.push({ title, url, category, status: 'unreachable' });
        }
      }
    } catch(e) {}
  }
} catch(e) {}

return { brokenLinks, brokenCount: brokenLinks.length, checkedCount };

const fs = require('fs');
const config = JSON.parse(fs.readFileSync('/home/node/config.json', 'utf8'));

const { brokenLinks, brokenCount, checkedCount } = $('Check broken links').item.json;
if (brokenCount === 0) return { skipped: true };

let text = '🔗 Broken Links Report\n\n';
text += checkedCount + ' links checked, ' + brokenCount + ' broken\n\n';
text += brokenLinks.map((l, i) =>
  `${i + 1}. ${l.title}\n❌ ${l.status}\n📂 ${l.category}\n${l.url}`
).join('\n\n');

await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://api.telegram.org/bot' + config.telegram_bot_token + '/sendMessage',
  headers: { 'Content-Type': 'application/json' },
  body: {
    chat_id: config.telegram_chat_id,
    text: text.slice(0, 4096)
  }
});

return { sent: true, brokenCount };
